sys_security_acl.script:
answer = false;

// Full access for application_admin
if (gs.hasRole('x_1909471_inspec_0.admin')) {
    answer = true;
}

// Restricted access for full filler
else if (gs.hasRole('x_1909471_inspec_0.user')) {

    if (current.isNewRecord()) {
        answer = true;
    }
    else if (current.assigned_to == gs.getUserID()) {
        answer = true;
    }
}
